// Declare a typed array of strings — a shopping list
let shoppingList: string[] = ['Milk', 'Bread', 'Eggs'];
// Add items to the end of the array using push
shoppingList.push('Butter');
shoppingList.push('Apples');
// Remove the last item using pop (returns the removed item)
const removedItem: string | undefined = shoppingList.pop();
console.log('Removed:', removedItem);
// Access elements by index (0-based)
const firstItem: string = shoppingList[0];
console.log('First item:', firstItem);
// Get the current length of the array
console.log('List length:', shoppingList.length);
// Print all items
console.log('Shopping list:', shoppingList);
// Expected:
// Removed: Apples
// First item: Milk
// List length: 4
// Shopping list: [ 'Milk', 'Bread', 'Eggs', 'Butter' ]
